from typing import List

def main():
    serialization_service = DefaultSerializationServiceBuilder().build()

    data = [1, 2, 3, 4, 5]
    serialized_data = serialize_data(serialization_service, data)
    deserialized_data = deserialize_data(serialization_service, serialized_data)

    print("Original Data:", data)
    print("Serialized Data:", serialized_data)
    print("Deserialized Data:", deserialized_data)

def serialize_data(service: DefaultSerializationService, data: List[int]) -> bytes:
    """Serialize a list of integers using the provided serialization service."""
    return service.to_bytes(data)

def deserialize_data(service: DefaultSerializationService, data: bytes) -> List[int]:
    """Deserialize bytes back to a list of integers using the provided serialization service."""
    return service.from_bytes(data)

if __name__ == "__main__":
    main()
